To create a simple Discord bot using Discord.js v14 with a slash command to ban users, you'll need to follow these steps:

1. Initialize your project and install Discord.js v14:
   ```
   npm init -y
   npm install discord.js@14
   ```

2. Create a new file for your bot, e.g., `bot.js`.

3. Write the code for the bot:

```javascript
const { Client, GatewayIntentBits, REST, Routes } = require('discord.js');
const { token, clientId, guildId } = require('./config.json'); // Make sure to create a config.json with your bot's token, clientId, and guildId

const client = new Client({ intents: [GatewayIntentBits.Guilds] });

client.once('ready', () => {
    console.log('Ready!');

    const rest = new REST({ version: '10' }).setToken(token);

    (async () => {
        try {
            console.log('Started refreshing application (/) commands.');

            await rest.put(Routes.applicationGuildCommands(clientId, guildId), {
                body: [
                    {
                        name: 'ban',
                        description: 'Bans a user from the server',
                        options: [
                            {
                                type: 6, // USER type
                                name: 'user',
                                description: 'The user to ban',
                                required: true,
                            },
                        ],
                    },
                ],
            });

            console.log('Successfully reloaded application (/) commands.');
        } catch (error) {
            console.error(error);
        }
    })();
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isChatInputCommand()) return;

    const { commandName } = interaction;

    if (commandName === 'ban') {
        const user = interaction.options.getUser('user');

        if (!user) {
            await interaction.reply('You need to specify a user to ban!');
            return;
        }

        const member = interaction.guild.members.cache.get(user.id);

        if (!member) {
            await interaction.reply('User is not in the server.');
            return;
        }

        // Check if the bot has permissions to ban the user
        if (!interaction.guild.me.permissions.has("BanMembers")) {
            await interaction.reply('I do not have the permission to ban members.');
            return;
        }

        // Check if the target user is bannable by the bot
        if (!member.bannable) {
            await interaction.reply('I cannot ban this user.');
            return;
        }

        member.ban().then(() => {
            interaction.reply(`Successfully banned ${user.tag}`);
        }).catch(err => {
            interaction.reply('There was an error trying to ban this user: ' + err.message);
        });
    }
});

client.login(token);
```

4. Create a `config.json` file with your bot's `token`, `clientId`, and `guildId`:

```json
{
    "token": "YOUR_BOT_TOKEN",
    "clientId": "YOUR_CLIENT_ID",
    "guildId": "YOUR_GUILD_ID"
}
```

Replace `"YOUR_BOT_TOKEN"`, `"YOUR_CLIENT_ID"`, and `"YOUR_GUILD_ID"` with your actual bot token, client ID, and server (guild) ID.

5. Run your bot:

```
node bot.js
```

This code sets up a Discord bot that listens for the `/ban` slash command and attempts to ban the specified user from the server. Make sure that your bot has the required permissions (`BanMembers`) in the server to execute the ban command.

Here is a simple C++ function that converts a subset of Markdown to HTML. This function handles paragraphs, and bold and italic text, which are denoted in Markdown by `**` or `__` for bold, and `*` or `_` for italic.

```cpp
#include <string>
#include <regex>

std::string markdownToHTML(std::string& markdown) {
    std::string html = markdown;

    // Convert bold (**text** or __text__) to <strong>text</strong>
    std::regex bold_pattern(R"((\*\*|__)(.*?)\1)");
    html = std::regex_replace(html, bold_pattern, "<strong>$2</strong>");

    // Convert italic (*text* or _text_) to <em>text</em>
    std::regex italic_pattern(R"((\*|_)(.*?)\1)");
    html = std::regex_replace(html, italic_pattern, "<em>$2</em>");

    // Convert paragraphs separated by newlines to <p>text</p>
    std::regex paragraph_pattern(R"((\r\n|\r|\n){2,})");
    html = std::regex_replace(html, paragraph_pattern, "</p><p>");
    html = "<p>" + html + "</p>"; // Wrap the whole text in <p> tags
    html = std::regex_replace(html, std::regex(R"((\r\n|\r|\n))"), "<br>"); // Replace single newlines with <br>

    // Remove potentially added extra <p> tags around <br>
    html = std::regex_replace(html, std::regex(R"(<p><br>)"), "<br>");
    html = std::regex_replace(html, std::regex(R"(<br></p>)"), "<br>");

    return html;
}

// Usage example:
// std::string markdown = "This is **bold** and this is *italic*.\n\nThis is a new paragraph.";
// std::string html = markdownToHTML(markdown);
```

This function uses regular expressions to find and replace Markdown syntax with HTML tags. Please note that this is a very simplistic converter and does not cover all Markdown features. A complete Markdown to HTML converter would need to handle lists, headers, blockquotes, code blocks, links, images, and more, and would be significantly more complex.

